+// Translated from libfuse's example/poll.c:
+//    Copyright (C) 2008       SUSE Linux Products GmbH
+//    Copyright (C) 2008       Tejun Heo <teheo@suse.de>
+//
+// Translated to Rust/fuser by Zev Weiss <zev@bewilderbeest.net>
