+    #[cfg(feature = "abi-7-28")]
+    {
+        let mut flags = INIT_FLAGS;
+        if capabilities & FUSE_MAX_PAGES != 0 {
+            flags |= FUSE_MAX_PAGES;
+        }
+        flags
+    }
