+/// Configuration of the fuse kernel module connection
+#[derive(Debug)]
+pub struct KernelConfig {
+    capabilities: u64,
+    requested: u64,
+    max_readahead: u32,
+    max_max_readahead: u32,
+    max_background: u16,
+    congestion_threshold: Option<u16>,
+    max_write: u32,
+    #[cfg(feature = "abi-7-23")]
+    time_gran: Duration,
+    #[cfg(feature = "abi-7-40")]
+    max_stack_depth: u32,
