+    #[allow(clippy::too_many_arguments)]
+    pub(crate) fn new_statfs(
+        blocks: u64,
+        bfree: u64,
+        bavail: u64,
+        files: u64,
+        ffree: u64,
+        bsize: u32,
+        namelen: u32,
+        frsize: u32,
+    ) -> Self {
+        let r = abi::fuse_statfs_out {
+            st: abi::fuse_kstatfs {
+                blocks,
+                bfree,
+                bavail,
+                files,
+                ffree,
+                bsize,
+                namelen,
+                frsize,
+                padding: 0,
+                spare: [0; 6],
