+/// Filesystem operation (and arguments) the kernel driver wants us to perform. The fields of each
+/// variant needs to match the actual arguments the kernel driver sends for the specific operation.
+#[derive(Debug)]
+#[allow(missing_docs)]
+pub enum Operation<'a> {
+    Lookup(Lookup<'a>),
+    Forget(Forget<'a>),
+    GetAttr(GetAttr<'a>),
+    SetAttr(SetAttr<'a>),
+    #[allow(dead_code)]
+    ReadLink(ReadLink<'a>),
+    SymLink(SymLink<'a>),
+    MkNod(MkNod<'a>),
+    MkDir(MkDir<'a>),
+    Unlink(Unlink<'a>),
+    RmDir(RmDir<'a>),
+    Rename(Rename<'a>),
+    Link(Link<'a>),
+    Open(Open<'a>),
+    Read(Read<'a>),
+    Write(Write<'a>),
+    #[allow(dead_code)]
+    StatFs(StatFs<'a>),
+    Release(Release<'a>),
+    FSync(FSync<'a>),
+    SetXAttr(SetXAttr<'a>),
+    GetXAttr(GetXAttr<'a>),
+    ListXAttr(ListXAttr<'a>),
+    RemoveXAttr(RemoveXAttr<'a>),
+    Flush(Flush<'a>),
+    Init(Init<'a>),
+    OpenDir(OpenDir<'a>),
+    ReadDir(ReadDir<'a>),
+    ReleaseDir(ReleaseDir<'a>),
+    FSyncDir(FSyncDir<'a>),
+    GetLk(GetLk<'a>),
+    SetLk(SetLk<'a>),
+    SetLkW(SetLkW<'a>),
+    Access(Access<'a>),
+    Create(Create<'a>),
+    Interrupt(Interrupt<'a>),
+    BMap(BMap<'a>),
+    Destroy(Destroy<'a>),
+    IoCtl(IoCtl<'a>),
+    Poll(Poll<'a>),
+    #[allow(dead_code)]
+    NotifyReply(NotifyReply<'a>),
+    BatchForget(BatchForget<'a>),
+    #[cfg(feature = "abi-7-19")]
+    FAllocate(FAllocate<'a>),
+    #[cfg(feature = "abi-7-21")]
+    ReadDirPlus(ReadDirPlus<'a>),
+    #[cfg(feature = "abi-7-23")]
+    Rename2(Rename2<'a>),
+    #[cfg(feature = "abi-7-24")]
+    Lseek(Lseek<'a>),
+    #[cfg(feature = "abi-7-28")]
+    CopyFileRange(CopyFileRange<'a>),
+
+    #[cfg(target_os = "macos")]
+    SetVolName(SetVolName<'a>),
+    #[cfg(target_os = "macos")]
+    GetXTimes(GetXTimes<'a>),
+    #[cfg(target_os = "macos")]
+    Exchange(Exchange<'a>),
+
+    #[allow(dead_code)]
+    CuseInit(CuseInit<'a>),
+}
